    for i in range(2,n+1):
        if is_prime(i):
            prime_numbers.append(i)

    prime_pairs = []
    for prime1 in prime_numbers:
        for prime2 in prime_numbers:
            if prime1 + prime2 > n:
                break
            prime_pairs.append((prime1,prime2))

