class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_end_of_word = False

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word):
        node = self.root
        for char in word:
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_end_of_word = True

    def search(self, prefix):
        node = self.root
        for char in prefix:
            if char not in node.children:
                return False
            node = node.children[char]
        return node.is_end_of_word

def min_leftovers(s, word_list):
    # Build Trie from dictionary words
    trie = Trie()
    for word in word_list:
        trie.insert(word)

    min_leftovers = len(s)
    start = 0
    end = 0
    word = ""

    while end < len(s):
        # Check if substring "word" is a valid word
        if trie.search(word + s[end]):
            word += s[end]
            min_leftovers -= len(word)
            start = end
        end += 1

    return min_leftovers
